import React from 'react';
import './Stock.css'

function DisplayStockData({ stockData }) {
  if (!stockData) {
    return <p>Enter a symbol to fetch data</p>;
  }
  const arrow = stockData.pChange > 0 ? '&#9650;' : '&#9660;';
  const isStockUp = stockData.change > 0;


  return (
    <div className='info'>
      <p style={{color: isStockUp ? "yellow" : "red"}}>{stockData.symbol} {stockData.price}</p>
      <p style={{color: isStockUp ? "yellow" : "red"}}>{stockData.change} {arrow}{stockData.pChange}</p>
    </div>
  );
}

export default DisplayStockData;
